// // This module implements a 32-bit wide, synchronous 2-to-1 multiplexer with reset functionality. On a rising clock edge, if the reset signal is high, the output is set to one. If reset is low and the select signal (sel) is high, the output will take the value of a; otherwise, it will take the value of b.
module top_module( clk,reset,a,b,sel,out);parameter width=32;
input [width-1:0]a,b;
input sel,clk,reset;
output reg [width-1:0] out;

always@(posedge clk)
begin
if (reset)
out=32'b0;

else if (sel)
out=b;
else
out=a;
end
endmodule
